import zlib, base64, json
from functools import lru_cache
from typing import Optional

_DATA = ""

_ALIASES = {"AUSTRALIA": "AU", "BRUNEI": "BN", "BRUNEI DARUSSALAM": "BN", "CHINA": "CN", "PEOPLE'S REPUBLIC OF CHINA": "CN", "INDONESIA": "ID", "JAPAN": "JP", "CAMBODIA": "KH", "KOREA": "KR", "SOUTH KOREA": "KR", "REPUBLIC OF KOREA": "KR", "LAOS": "LA", "LAO PDR": "LA", "LAO PEOPLE'S DEMOCRATIC REPUBLIC": "LA", "MYANMAR": "MM", "MALAYSIA": "MY", "NEW ZEALAND": "NZ", "PHILIPPINES": "PH", "SINGAPORE": "SG", "VIETNAM": "VN", "VIET NAM": "VN"}

@lru_cache(maxsize=1)
def _load() -> dict:
    return json.loads(zlib.decompress(base64.b64decode(_DATA)).decode('utf-8'))

def _normalize_country(country: str) -> str:
    c = country.strip().upper()
    return _ALIASES.get(c, c[:2] if len(c) >= 2 else c)

def get_fta_form(hs_code: str, origin_country: str) -> Optional[str]:
    """
    Return FTA form name if hs_code qualifies for preferential treatment
    from origin_country. Returns None if no FTA applies.
    
    hs_code: 6 or 8 digit string
    origin_country: ISO2 code (TH, AU, JP...) or full name
    """
    db = _load()
    cc = _normalize_country(origin_country)
    country_db = db.get(cc)
    if not country_db:
        return None
    
    clean = hs_code.replace(" ", "").replace(".", "")
    # Try 8-digit, 7-digit, 6-digit fallbacks
    for length in [8, 7, 6]:
        key = clean[:length].ljust(length, "0")
        if key in country_db:
            return country_db[key]
        key2 = clean[:length]
        if key2 in country_db:
            return country_db[key2]
    return None

def get_eligible_countries(hs_code: str) -> list:
    """Return list of (country_code, fta_form) tuples where this HS code qualifies."""
    db = _load()
    clean = hs_code.replace(" ", "").replace(".", "")
    result = []
    for cc, country_db in db.items():
        for length in [8, 7, 6]:
            key = clean[:length]
            if key in country_db:
                result.append((cc, country_db[key]))
                break
    return result

